 1	import { Checkbox, Radio, Text, TextVariants, Tooltip } from '@patternfly/react-core';
 2	import { InfoAltIcon } from '@patternfly/react-icons';
 3	import * as _ from 'lodash';
 4	import * as React from 'react';
 5	import { useTranslation } from 'react-i18next';
 6	
 7	export type Size = 's' | 'm' | 'l';
 8	
 9	export interface TableDisplayOptionsProps {
10	  size: Size;
11	  setSize: (v: Size) => void;
12	  showDuplicates: boolean;
13	  setShowDuplicates: (showDuplicates: boolean) => void;
14	}
15	
16	export const TableDisplayOptions: React.FC<TableDisplayOptionsProps> = ({
17	  size,
18	  setSize,
19	  showDuplicates,
20	  setShowDuplicates
21	}) => {
22	  const { t } = useTranslation('plugin__netobserv-plugin');
23	
24	  const sizeOptions = {
25	    s: t('Compact'),
26	    m: t('Normal'),
27	    l: t('Large')
28	  };
29	
30	  return (
31	    <>
32	      <div className="pf-v6-c-menu__group">
33	        <Tooltip content={t('Force table rows to specific sizing.')}>
34	          <div className="pf-v6-c-menu__group-title">
35	            <Text component={TextVariants.p}>
36	              {t('Row size')} <InfoAltIcon />
37	            </Text>
38	          </div>
39	        </Tooltip>
40	        {_.map(sizeOptions, (name, key) => {
41	          return (
42	            <div key={`size-${key}`}>
43	              <label className="display-dropdown-padding pf-v6-c-menu__menu-item">
44	                <Radio
45	                  isChecked={key === size}
46	                  name={`size-${key}`}
47	                  onChange={() => setSize(key as Size)}
48	                  label={name}
49	                  data-test={`size-${key}`}
50	                  id={`size-${key}`}
51	                  value={key}
52	                />
53	              </label>
54	            </div>
55	          );
56	        })}
57	      </div>
58	      <div className="pf-v6-c-menu__group">
59	        <Tooltip
60	          content={t(
61	            // eslint-disable-next-line max-len
62	            'A flow might be reported from both source and destination nodes, making it appear several times. By default, duplicates are merged, but you can show them in order to get more granular data.'
63	          )}
64	        >
65	          <div className="pf-v6-c-menu__group-title">
66	            <Text component={TextVariants.p}>
67	              {t('Duplicated flows')} <InfoAltIcon />
68	            </Text>
69	          </div>
70	        </Tooltip>
71	        <label className="display-dropdown-padding pf-v6-c-menu__menu-item">
72	          <Checkbox
73	            isChecked={showDuplicates}
74	            name={'show-duplicates'}
75	            onChange={() => setShowDuplicates(!showDuplicates)}
76	            label={t('Show duplicates')}
77	            data-test={'show-duplicates'}
78	            id={'show-duplicates'}
79	          />
80	        </label>
81	      </div>
82	    </>
83	  );
84	};
85	
86	export default TableDisplayOptions;

